with open("template.html", "r", encoding="utf-8") as f:
    template = f.read()

for biz in businesses:
    css = template
    for key, val in [("{{PRIMARY_COLOR}}", biz["primary"]), ("{{PRIMARY_DARK}}", biz["primary_dark"]),
                     ("{{ACCENT_COLOR}}", biz["accent"]), ("{{BG_COLOR}}", biz["bg"]), ("{{BG_ALT}}", biz["bg_alt"]),
                     ("{{TEXT_COLOR}}", biz["text"]), ("{{TEXT_LIGHT}}", biz["text_light"]),
                     ("{{HERO_GRADIENT_END}}", biz["hero_end"]), ("{{BUSINESS_NAME}}", biz["name"]), ("{{TAGLINE}}", biz["tagline"])]:
        css = css.replace(key, val)

    nav_links = "".join(f'<li><a href="#">{i}</a></li>' for i in biz["nav"].split("|"))
    features = "\n".join(f'<div class="feature-item"><div class="icon">{i}</div><h4>{t}</h4><p>{d}</p></div>' for i,t,d in biz["features"])
    cards = "\n".join(f'<div class="card"><div class="card-img">{t}</div><div class="card-body"><h3>{t}</h3><p>{d}</p></div></div>' for t,d in biz["cards"])
    tests = "\n".join(f'<div class="testimonial"><div class="stars">&#9733;&#9733;&#9733;&#9733;&#9733;</div><p>{q}</p><div class="author">{a}</div></div>' for q,a in biz["testimonials"])

    parts = biz["name"].split(" ", 1)
    logo = f'{parts[0]} <span>{parts[1] if len(parts)>1 else ""}</span>'

    body = f'''
<nav><div class="inner"><div class="logo serif">{logo}</div><ul>{nav_links}</ul><a href="#" class="cta-btn">{biz["cta"]}</a></div></nav>
<section class="hero"><div class="hero-content"><div class="hero-badge">{biz["town"]}</div><h1 class="serif">{biz["hero_title"]}</h1><p>{biz["hero_desc"]}</p><div class="hero-buttons"><a href="#" class="btn-primary">{biz["cta"]} &#8594;</a><a href="#" class="btn-secondary">Learn More</a></div></div></section>
<div class="features-strip"><div class="inner">{features}</div></div>
<section class="about-section"><div class="section-inner about-grid"><div class="about-image">{biz["about_quote"]}</div><div class="about-text"><h2 class="serif">{biz["about_title"]}</h2><p>{biz["about_p1"]}</p><p>{biz["about_p2"]}</p></div></div></section>
<section><div class="section-inner"><div class="section-header"><div class="overline">What We Offer</div><h2 class="serif">Our Services</h2></div><div class="cards-grid">{cards}</div></div></section>
<section class="testimonials"><div class="section-inner"><div class="section-header"><div class="overline">Reviews</div><h2 class="serif">What People Are Saying</h2></div><div class="testimonial-grid">{tests}</div></div></section>
<section class="cta-banner"><h2 class="serif">{biz["cta_title"]}</h2><p>{biz["cta_desc"]}</p><a href="#" class="btn-primary">{biz["cta"]} &#8594;</a></section>
<footer><div class="inner"><div><div class="brand serif">{biz["name"]}</div><p>{biz["footer_desc"]}</p></div><div><h4>Quick Links</h4>{"".join(f"<a href=\\'#\\'>{i}</a><br>" for i in biz["nav"].split("|")[:4])}</div><div><h4>Contact</h4><p>{biz["town"]}</p><p>{biz["footer_phone"]}</p></div><div><h4>Hours</h4><p>See website</p></div></div><div class="bottom">Design concept by RAGA Marketing &mdash; ragamarketing.com</div></footer>'''

    html = css.replace("{{BODY_CONTENT}}", body)
    with open(f'{biz["slug"]}.html', "w", encoding="utf-8") as f:
        f.write(html)
    print(f'Created: {biz["slug"]}.html')

print(f"\nDone! {len(businesses)} mockups generated.")
